// Emite 1 item por workflow ativo que tem trigger próprio.
// Exclui sub-workflows (executeWorkflowTrigger sem schedule/webhook).
const body = $input.first().json;
const workflows = body.data || [];
const out = [];
for (const wf of workflows) {
  if ((wf.triggerCount || 0) === 0) continue;
  out.push({ json: { workflow_id: wf.id, workflow_name: wf.name, triggerCount: wf.triggerCount } });
}
return out;

// Emite item APENAS se workflow está silent (>24h sem exec) ou última foi erro.
const items = $input.all();
const out = [];
const NOW = Date.now();
const H24_MS = 24 * 60 * 60 * 1000;
for (let i = 0; i < items.length; i++) {
  const upstream = $('Filter Has Trigger').itemMatching(i).json;
  const wfId = upstream.workflow_id;
  const wfName = upstream.workflow_name;
  const body = items[i].json || {};
  const execs = body.data || [];
  const last = execs[0];
  if (!last) {
    out.push({ json: { workflow_id: wfId, workflow_name: wfName, reason: 'never_executed', hours_ago: null, exec_id: null, status: null } });
    continue;
  }
  const startedAt = last.startedAt ? new Date(last.startedAt).getTime() : 0;
  const hoursAgo = startedAt ? Math.round((NOW - startedAt) / 3600000) : null;
  if (last.status === 'error') {
    out.push({ json: { workflow_id: wfId, workflow_name: wfName, reason: 'last_was_error', hours_ago: hoursAgo, exec_id: last.id, status: 'error' } });
  } else if (hoursAgo !== null && hoursAgo > 24) {
    out.push({ json: { workflow_id: wfId, workflow_name: wfName, reason: 'stale_>24h', hours_ago: hoursAgo, exec_id: last.id, status: last.status } });
  }
}
return out;

